    { name: { en: 'Lime juice', ro: 'suc de lamaie verde', ru: 'сок лайма', es: 'jugo de lima' }, measure: 'To taste' },
    { name: { en: 'Sugar', ro: 'zahar', ru: 'сахар', es: 'azucar' }, measure: 'To taste' },
    { name: { en: 'Red Chilli', ro: 'ardei iute rosu', ru: 'красный чили', es: 'chile rojo' }, measure: 'To serve' }
