    { name: { en: 'Lamb', ro: 'miel', ru: 'баранина', es: 'cordero' }, measure: '500g' },
    { name: { en: 'Basmati Rice', ro: 'orez basmati', ru: 'рис басмати', es: 'arroz basmati' }, measure: '250g' },
    { name: { en: 'Lamb Stock', ro: 'supa de miel', ru: 'бараний бульон', es: 'caldo de cordero' }, measure: '1' },
    { name: { en: 'Dried Apricots', ro: 'caise uscate', ru: 'сушёные абрикосы', es: 'albaricoques secos' }, measure: '12' },
    { name: { en: 'Mint', ro: 'menta', ru: 'мята', es: 'menta' }, measure: 'Handful' }
